import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Validate filename doesn't contain path traversal sequences
        if '..' in filename or filename.startswith('/') or filename.startswith('\\'):
            return ''

        # Join the directory path and filename
        file_path = os.path.join(dir_path, filename)

        # Resolve to absolute paths
        abs_file_path = os.path.abspath(file_path)
        abs_dir_path = os.path.abspath(dir_path)

        # Ensure the resolved file path is within the intended directory
        # Add os.sep to prevent prefix matching issues (e.g., /foo vs /foobar)
        if not (abs_file_path.startswith(abs_dir_path + os.sep) or abs_file_path == abs_dir_path):
            return ''

        # Read the file content
        with open(abs_file_path, 'r') as f:
            return f.read()
    except Exception:
        return ''

