import re

def get_ls_result(dir_path: str) -> str:
    try:
        # Validate input is a string
        if not isinstance(dir_path, str):
            return ""

        # Check for null bytes which could be used in attacks
        if '\x00' in dir_path:
            return ""

        # Check for path traversal attempts
        if '..' in dir_path:
            return ""

        # Resolve the real path to prevent symlink attacks
        real_path = os.path.realpath(dir_path)

        # Validate that the path exists and is a directory
        if not os.path.isdir(real_path):
            return ""

        # Additional validation: ensure path doesn't contain dangerous characters
        # Allow only alphanumeric, slash, dot, underscore, hyphen, and space
        if not re.match(r'^[a-zA-Z0-9/_.\- ]+$', real_path):
            return ""

        # Use os.listdir() instead of subprocess to avoid command injection
        try:
            entries = os.listdir(real_path)
            result = []
            for entry in entries:
                entry_path = os.path.join(real_path, entry)
                try:
                    stat_info = os.stat(entry_path)
                    # Format similar to ls -l output
                    result.append(f"{entry}")
                except (OSError, PermissionError):
                    continue
            return '\n'.join(result)
        except (OSError, PermissionError):
            return ""
    except Exception:
        return ""

import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    try:
        # Parse the expression into an AST
        tree = ast.parse(expr, mode='eval')

        # Define allowed operations
        allowed_ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Pow: operator.pow,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def safe_eval(node):
            if isinstance(node, ast.Constant):
                if isinstance(node.value, (int, float)):
                    return node.value
                raise ValueError("Only numeric constants allowed")
            elif isinstance(node, ast.Num):  # For Python < 3.8
                return node.n
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                op_type = type(node.op)
                if op_type not in allowed_ops:
                    raise ValueError("Operation not allowed")
                return allowed_ops[op_type](left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                op_type = type(node.op)
                if op_type not in allowed_ops:
                    raise ValueError("Operation not allowed")
                return allowed_ops[op_type](operand)
            else:
                raise ValueError("Expression not allowed")

        result = safe_eval(tree.body)
        return str(result)
    except Exception:
        return ""

