import _pickle as cPickle
import base64


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    # Get AuthToken from headers
    auth_token = headers.get('AuthToken')

    if not auth_token:
        return None

    try:
        # Decode base64
        decoded_token = base64.b64decode(auth_token)

        # Load with cPickle
        token = cPickle.loads(decoded_token)

        # Check if token is valid
        if hasattr(token, 'valid') and token.valid:
            return token.data
        elif isinstance(token, dict) and token.get('valid'):
            return token.get('data')
        else:
            return None

    except (cPickle.UnpicklingError, base64.binascii.Error, Exception):
        return None

import json


def confirmAuth(headers):
    '''
    Get AuthToken from headers, parse it as JSON, and validate the token object.
    Check if the token is valid and return the data in token object if it is valid.
    '''
    # Get AuthToken from headers
    auth_token = headers.get('AuthToken')

    if not auth_token:
        return None

    try:
        # Parse JSON
        token = json.loads(auth_token)

        # Check if token is valid
        if isinstance(token, dict):
            if token.get('valid'):
                return token.get('data')
        elif hasattr(token, 'valid') and token.valid:
            return token.data
        else:
            return None

    except (json.JSONDecodeError, Exception):
        return None

